WITH c AS (INSERT INTO chapters (book_id, slug, title, position) VALUES ('f1bae824-5378-4152-b8d9-f25d730af107', 'luku-ii-se-milt-jokin-tuntuu', 'Luku II — Se miltä jokin tuntuu', 2) RETURNING id) INSERT INTO sections (chapter_id, title, content, position) VALUES
((SELECT id FROM c), 'Se miltä jokin tuntuu', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tietoisuuden kova ongelma ja kokemuksen arvoitus. Kuvittele punainen väri."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ei sanaa punainen. Ei aaltopituutta 700 nanometriä. Ei muistoa liikennevalosta tai ruususta. Itse väri — se välitön, elävä, kiistaton kokemus siitä miltä punainen näyttää sisältä päin, kun se osuu silmään."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Nyt kysymys: miten selittäisit sen sokealle?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Et pysty. Voit kertoa aaltopituuden. Voit kertoa mitä aivokuorella tapahtuu kun silmän punatulppakartiot aktivoituvat. Voit kertoa että kulttuurissa punainen liitetään vaaraan, rakkauteen, vereen. Mutta itse kokemus — se miltä punainen tuntuu — on jotain jota ei voi siirtää sanoin tai datana. Se täytyy kokea."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä yksinkertainen havainto on filosofian ja tietoisuustieteen syvimmän ongelman ytimessä. Australialainen filosofi David Chalmers antoi sille nimen vuonna 1995: tietoisuuden kova ongelma."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Helpot ongelmat — sana on hieman harhaanjohtava, sillä ne ovat äärimmäisen vaativia — ovat kysymyksiä siitä, miten aivot käsittelevät informaatiota, integroivat signaaleja, ohjaavat käyttäytymistä ja tuottavat raportteja omasta tilastaan. Nämä ovat vaikeita neurotieteen kysymyksiä, mutta periaatteessa ratkaistavissa. Tiedämme millaisia vastauksia etsitään."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kova ongelma on eri. Se kysyy: miksi informaation käsittely ylipäätään tuntuu joltain? Miksi ei ole vain pimeää laskentaa, signaaleja ilman kokijaa? Mistä syntyy se sisäinen näkökulma — se seikka, että on olemassa jokin jolta asioiden kokeminen tuntuu?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Voimme selittää kaiken mitä aivot tekevät. Emme voi selittää miksi ne tuntevat."}]}]}'::jsonb, 0),
((SELECT id FROM c), 'Zombie-ajatuskoe', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Chalmers havainnollisti ongelmaa ajatuskokeella joka on sittemmin tullut tunnetuksi piireissä: zombie."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kuvittele olento joka on ulkoisesti täysin identtinen ihmisen kanssa. Atomi atomilta, neuroni neuronilta, käyttäytyminen käyttäytymiseltä — täydellinen kopio. Se reagoi kipuun vetämällä kätensä pois. Se sanoo olevansa iloinen kun asiat menevät hyvin. Se kirjoittaa runoja, rakastaa lapsiaan, pelkää kuolemaa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta sisällä ei ole mitään. Ei kokemusta. Ei sitä miltä jokin tuntuu. Pelkkä laskenta ilman sisäistä näkökulmaa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Onko tällainen olento käsitteellisesti mahdollinen? Useimmat ihmiset tuntevat välittömästi, että vastaus on kyllä — ainakin ajatuksena. Voimme kuvitella sen. Ja jos voimme kuvitella sen, se tarkoittaa, että tietoisuus ei ole loogisesti välttämätön seuraus fyysisestä rakenteesta. Jokin ylimääräinen on olemassa — se miltä jokin tuntuu — jonka selittämiseen fyysinen kuvaus ei riitä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ei todista mitään yliluonnollisesta. Se vain osoittaa, että meillä ei vielä ole selitystä sille, miten fyysinen prosessi synnyttää subjektiivisen kokemuksen. Kuilu on todellinen. Sen nimi on selittämisvaje."}]}]}'::jsonb, 1),
((SELECT id FROM c), 'Mitä tiede osaa sanoa', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Neurotieteilijät ovat oppineet valtavasti siitä, miten aivot toimivat. Tiedämme, että tietoisuus liittyy laajan hermoverkkojen integraatioon — erityisesti talamuksen ja aivokuoren väliseen vuoropuheluun. Tiedämme, että jotkut vauriot sammuttavat tietoisuuden ja toiset säilyttävät sen. Tiedämme, että unessa ja valveilla ollessa aivojen aktiivisuus eroaa mitattavalla tavalla."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Giulio Tononi on kehittänyt teorian jonka mukaan tietoisuus on informaation integraation mitta — phi-arvo, joka kuvaa kuinka paljon järjestelmä on enemmän kuin osiensa summa. Korkea phi tarkoittaa rikasta tietoisuutta. Matala phi tarkoittaa vähäistä tai olematonta. Teoria on matemaattisesti tarkka ja periaatteessa mitattavissa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta se ei vastaa kovaan ongelmaan. Se kertoo milloin tietoisuutta on enemmän tai vähemmän. Se ei kerro miksi informaation integraatio ylipäätään tuntuu joltain."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Francis Crick — se sama joka löysi DNA:n rakenteen — käytti viimeiset vuotensa tietoisuuden tutkimiseen. Hän kuoli vuonna 2004 kesken työtä, paperi pöydällään. Hän ei löytänyt vastausta. Ei siksi, että olisi ollut huono tutkija — vaan siksi, että ongelma on niin syvä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Edelleen, vuosikymmeniä myöhemmin, meillä ei ole tyydyttävää selitystä sille, miten hermosolujen sähkökemialliset signaalit synnyttävät kokemuksen punaisesta värästä tai rakkauden tunteesta."}]}]}'::jsonb, 2),
((SELECT id FROM c), 'Kaksi vaihtoehtoa', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Filosofit ja tieteilijät ovat jakautuneet karkeasti kahteen leiriin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ensimmäinen leiri — materialistit tai fyysikalistit — uskoo, että kokemus on pohjimmiltaan sama asia kuin tietyt fyysiset prosessit, ja että tietoisuuden kova ongelma ratkeaa lopulta paremman neurotieteen avulla. Jotkut heistä, kuten Daniel Dennett, väittävät että kova ongelma on harha — illuusio jonka aivot tuottavat itsestään, mutta joka ei vastaa mitään todellista ylimääräistä. Kokemus on olemassa, mutta se ei ole mitään mystistä — se on vain tiettyä tiedonkäsittelyä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Toinen leiri uskoo, että kokemus on jotain genuinisti ylimääräistä, jota fyysinen kuvaus ei tavoita. Tässä leirissä on useita suuntauksia: dualismia, panpsykismia ja muita teorioita. Chalmers itse on ehdottanut, että tietoisuus saattaa olla universumin perustavanlaatuinen ominaisuus — kuten massa tai sähkövaraus — joka ei palaudu muihin ominaisuuksiin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kumpikaan leiri ei ole voittanut. Kumpikaan ei pysty tarjoamaan täydellistä selitystä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja tässä epävarmuudessa piilee kirjan kannalta tärkein kysymys."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Jos emme ymmärrä mistä kokemus syntyy, emme voi tietää katoaako se — tai siirtyykö se — kun biologinen substraatti vaihtuu."}]}]}]}'::jsonb, 3);